insert into testimonials (name, role, company, initials, quote, rating, visible, sort_order) values ('Priya Nair', 'Product Manager', 'Artem Health Care', 'PN', 'Jaymin turned a vague accessibility mandate into an actual, working component library in weeks. Every form we shipped after that audit just worked for keyboard and screen-reader users — no follow-up tickets.', 5, true, 0);
insert into testimonials (name, role, company, initials, quote, rating, visible, sort_order) values ('Daniel Cho', 'Engineering Manager', 'Compito', 'DC', 'The board rebuild in React was the smoothest front-end migration I''ve been part of. Jaymin kept design and code in sync through Figma/Zeplin the whole way, so we never had that usual ''the build doesn''t match the file'' argument.', 5, true, 1);
insert into testimonials (name, role, company, initials, quote, rating, visible, sort_order) values ('Meera Shah', 'Lead Designer', 'Valyxto', 'MS', 'Most developers treat a dense data table as a styling problem. Jaymin treated it as an information-hierarchy problem, and the dashboard reads completely differently now — same data, actually scannable.', 5, true, 2);
insert into testimonials (name, role, company, initials, quote, rating, visible, sort_order) values ('Arjun Mehta', 'Junior UI Developer (mentee)', 'Augmented Tech Labs', 'AM', 'I learned more about CSS architecture and PR review from three months of pairing with Jaymin than from a year on my own. He explains the ''why'' behind every review comment, not just the fix.', 5, true, 3);
insert into testimonials (name, role, company, initials, quote, rating, visible, sort_order) values ('Sara Lindqvist', 'QA Lead', 'Artem Health Care', 'SL', 'The token-based component library cut our regression surface dramatically — once a pattern was fixed once, it was fixed everywhere it was used, not just in the one screen someone happened to notice.', 4, true, 4);
insert into testimonials (name, role, company, initials, quote, rating, visible, sort_order) values ('Rohan Deshpande', 'Freelance Client', 'Marketing Microsite (2019)', 'RD', 'Quick turnaround on the landing page redesign, responsive across every device we tested.', 4, false, 5);
