insert into philosophy_items (title, description, sort_order) values ('Accessibility is load-bearing', 'WCAG compliance isn''t a pass I do at the end — semantic HTML, keyboard flows, and screen-reader labeling get designed in from the first component, because retrofitting accessibility into a shipped UI is always more expensive than building it in.', 0);
insert into philosophy_items (title, description, sort_order) values ('Systems over one-offs', 'Every component I ship is a candidate for reuse. I''d rather spend an extra hour making a button variant-driven and token-based than watch three teams quietly reinvent it with slightly different padding six months from now.', 1);
insert into philosophy_items (title, description, sort_order) values ('Motion with intent', 'Animation should clarify state changes and guide attention, not perform for its own sake — and it should get out of the way entirely the moment a user asks for reduced motion.', 2);
insert into philosophy_items (title, description, sort_order) values ('Design and code are one conversation', 'The best interfaces come from tight feedback loops between Figma and the component library, not a one-way handoff. I''d rather flag a feasibility issue in the design review than silently work around it in code.', 3);
insert into skills (category, level, blurb, items, sort_order) values ('Frameworks', 92, 'Daily-driver frameworks for production UI work.', $jsonval$["Angular", "React"]$jsonval$::jsonb, 0);
insert into skills (category, level, blurb, items, sort_order) values ('UI Libraries', 88, 'Component libraries built and extended for enterprise-scale apps.', $jsonval$["PrimeNG", "PrimeReact"]$jsonval$::jsonb, 1);
insert into skills (category, level, blurb, items, sort_order) values ('Styling', 90, 'From utility-first to hand-rolled design tokens.', $jsonval$["SCSS", "Bootstrap", "Tailwind CSS"]$jsonval$::jsonb, 2);
insert into skills (category, level, blurb, items, sort_order) values ('Design Tools', 80, 'Where implementation starts — reading and reasoning about design files directly.', $jsonval$["Figma", "Zeplin"]$jsonval$::jsonb, 3);
insert into skills (category, level, blurb, items, sort_order) values ('Tooling', 75, 'Version control and collaboration workflows for cross-functional teams.', $jsonval$["Bitbucket", "GitLab"]$jsonval$::jsonb, 4);
insert into skills (category, level, blurb, items, sort_order) values ('Practices', 85, 'The non-visual half of good UI work.', $jsonval$["Accessibility (WCAG)", "Design Systems", "Code Review", "Mentorship"]$jsonval$::jsonb, 5);
insert into experience (role, company, period, description, achievements, stack, sort_order) values ('Sr. UI/UX Designer', 'Augmented Tech Labs', '2023 — Present', 'Leading design system implementation and UI architecture decisions across multiple product lines, mentoring junior developers on component-driven development and accessibility standards.', $jsonval$["Own architectural decisions for the shared component library used across every active product line, from token structure to versioning strategy.", "Run accessibility reviews on every new UI surface before release, treating WCAG conformance as a merge requirement rather than a follow-up task.", "Mentor a rotating group of junior and mid-level developers through pairing sessions, PR reviews, and componentization workshops."]$jsonval$::jsonb, $jsonval$["Angular", "PrimeNG", "SCSS", "Figma"]$jsonval$::jsonb, 0);
insert into experience (role, company, period, description, achievements, stack, sort_order) values ('UI Developer', 'Previous Company (update me)', '2022 — 2023', 'Owned front-end delivery for core product surfaces, translating Figma designs into production Angular components with a focus on performance and cross-browser consistency.', $jsonval$["Translated high-fidelity Figma designs into production Angular components as the primary front-end owner for the product's core surfaces.", "Audited cross-browser rendering issues systematically, closing out a long-standing backlog of visual regressions.", "Introduced lazy-loading and change-detection optimizations to keep list-heavy views responsive as data volume grew."]$jsonval$::jsonb, $jsonval$["Angular", "SCSS", "Figma"]$jsonval$::jsonb, 1);
insert into experience (role, company, period, description, achievements, stack, sort_order) values ('UI Developer', 'Previous Company (update me)', '2020 — 2022', 'Built and maintained a shared React component library adopted across three product teams, reducing duplicate UI work and standardizing design tokens.', $jsonval$["Designed and built a shared React component library from scratch, adopted by three separate product teams within the org.", "Standardized design tokens (color, spacing, typography) across previously divergent product surfaces.", "Wrote component documentation and usage guidelines that became the onboarding reference for new front-end hires."]$jsonval$::jsonb, $jsonval$["React", "Tailwind CSS", "Figma"]$jsonval$::jsonb, 2);
insert into experience (role, company, period, description, achievements, stack, sort_order) values ('Jr. UI Developer', 'Previous Company (update me)', 'March 2019 — 2020', 'Started my UI development career building responsive marketing and product pages, developing a strong foundation in semantic HTML, CSS architecture, and JavaScript fundamentals.', $jsonval$["Built responsive marketing and product pages from Figma/Zeplin handoff, developing an early, rigorous eye for pixel-accurate implementation.", "Established a personal foundation in semantic HTML and scalable CSS architecture that still shapes how I structure components today.", "Picked up JavaScript fundamentals on the job, moving from static pages to interactive UI within the first year."]$jsonval$::jsonb, $jsonval$["HTML", "CSS", "JavaScript", "Bootstrap"]$jsonval$::jsonb, 3);
